CustomField.formula:
/* If Top Line is Closed Won/Lost → do not show stations at all */

IF( 
				OR(
				MEDDPICC_Stations_Line__c ="",
				 CONTAINS(Name, 'Annual Price Increase') 
								)

				,'',


IF(
    CONTAINS(MEDDPICC_Status_Top_Line__c, "No Need To Qualify"),
   MEDDPICC_Status_Top_Line__c,

/* Otherwise → Top Line + stations (if exist) */
MEDDPICC_Status_Top_Line__c &  HYPERLINK(LEFT($Api.Partner_Server_URL_260, FIND( '/services', $Api.Partner_Server_URL_260)) &'flow/Opportunity_sc_Next_Stage?recordId=' &    Id , ' 🔗') &
IF(
    LEN(MEDDPICC_Stations_Line__c) > 0,
    BR() & MEDDPICC_Stations_Line__c,
    ""
)
)
			)
